const input = $input.all();
let redisValue = null;
if (input.length > 0 && input[0].json) {
  const keys = Object.keys(input[0].json);
  for (const k of keys) {
    if (k !== 'error' && input[0].json[k]) {
      redisValue = input[0].json[k];
      break;
    }
  }
}

let isAwaitingCancellation = false;
let isAwaiting1hConfirmation = false;
let bookingId = null;
let clientName = null;
let bookingInicio = null;

if (redisValue && typeof redisValue === 'string') {
  if (redisValue.startsWith('awaiting_cancellation')) {
    const parts = redisValue.split('|');
    isAwaitingCancellation = true;
    bookingId = parts[1] || null;
    clientName = parts[2] || null;
    bookingInicio = parts[3] || null;
  } else if (redisValue.startsWith('awaiting_1h_confirmation')) {
    const parts = redisValue.split('|');
    isAwaiting1hConfirmation = true;
    bookingId = parts[1] || null;
    clientName = parts[2] || null;
    bookingInicio = parts[3] || null;
  }
}

const hasActiveState = isAwaitingCancellation || isAwaiting1hConfirmation;

return [
  {
    json: {
      isAwaitingCancellation,
      isAwaiting1hConfirmation,
      hasActiveState,
      bookingId,
      clientName,
      bookingInicio
    }
  }
];

const dados = $('Dados').item.json;
const clean = (dados.senderPhone || dados.chatId).replace('@c.us', '').replace('@s.whatsapp.net', '').replace('@lid', '');
let number = clean.startsWith('55') ? clean.slice(2) : clean;
const ddd = number.slice(0, 2);
const rest = number.slice(2);

let formatWith9 = '';
let formatWithout9 = '';

if (rest.length === 9) {
  formatWith9 = `(${ddd}) ${rest.slice(0, 5)}-${rest.slice(5)}`;
  formatWithout9 = `(${ddd}) ${rest.slice(1, 5)}-${rest.slice(5)}`;
} else {
  formatWithout9 = `(${ddd}) ${rest.slice(0, 4)}-${rest.slice(4)}`;
  formatWith9 = `(${ddd}) 9${rest.slice(0, 4)}-${rest.slice(4)}`;
}

return [
  {
    json: {
      formatWith9,
      formatWithout9
    }
  }
];

const clients = $input.all();
let bookingFound = null;
let clientName = null;

for (const item of clients) {
  const client = item.json;
  if (client && client.agendamentos_base && client.agendamentos_base.length > 0) {
    const activeBookings = client.agendamentos_base.filter(b => b.status !== 'Cancelado');
    if (activeBookings.length > 0) {
      activeBookings.sort((a, b) => new Date(a.inicio) - new Date(b.inicio));
      const nearest = activeBookings[0];
      if (!bookingFound || new Date(nearest.inicio) < new Date(bookingFound.inicio)) {
        bookingFound = nearest;
        clientName = client.nome;
      }
    }
  }
}

if (!clientName && clients.length > 0) {
  clientName = clients[0].json.nome || null;
}

return [
  {
    json: {
      bookingFound,
      clientName
    }
  }
];

