for (const item of $input.all()) {
  const configData = $('Buscar Configs').all();
  const bookings = $input.all();

  const configs = {};
  for (const c of configData) {
    configs[c.json.chave] = c.json.valor;
  }

  const diasFuncionamento = configs.dias_funcionamento || [2, 3, 4, 5, 6, 0];
  const horariosDisponiveis = configs.horarios_disponiveis || ["18:30", "19:00", "19:30", "20:00", "20:30", "21:00", "21:30", "22:00"];
  const vagasPadrao = configs.vagas_padrao !== undefined ? configs.vagas_padrao : 5;
  const limitesCustomizados = configs.limites_customizados || {};

  const weekdaysPT = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sáb"];
  let resultText = "📅 *VAGAS E HORÁRIOS DISPONÍVEIS*\n*(Próximos 7 dias de funcionamento)*\n\n";

  const current = new Date();
  let daysCount = 0;

  for (let i = 0; i < 15; i++) {
    const dateObj = new Date(current.getTime() + i * 24 * 60 * 60 * 1000);
    const weekday = dateObj.getDay();

    if (!diasFuncionamento.includes(weekday)) continue;

    const weekdayLabel = weekdaysPT[weekday];
    const dateStrStr = dateObj.toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' });
    const year = dateObj.getFullYear();
    const month = String(dateObj.getMonth() + 1).padStart(2, '0');
    const day = String(dateObj.getDate()).padStart(2, '0');
    const dateKey = `${year}-${month}-${day}`;

    let dayAvailableSlots = [];

    for (const time of [...horariosDisponiveis].sort()) {
      const limit = limitesCustomizados[dateKey]?.[time] !== undefined 
        ? limitesCustomizados[dateKey][time] 
        : vagasPadrao;

      const occupied = bookings.filter(b => {
        if (!b.json.inicio) return false;
        const parts = b.json.inicio.split('T');
        const bDate = parts[0];
        const bTime = parts[1]?.slice(0, 5);
        return bDate === dateKey && bTime === time;
      }).length;

      const remaining = Math.max(0, limit - occupied);
      if (remaining > 0) {
        dayAvailableSlots.push(`${time} (${remaining}v)`);
      }
    }

    if (dayAvailableSlots.length > 0) {
      resultText += `*${weekdayLabel} (${dateStrStr}):*\n👉 ${dayAvailableSlots.join(' | ')}\n\n`;
    } else {
      resultText += `*${weekdayLabel} (${dateStrStr}):*\n❌ Esgotado\n\n`;
    }

    daysCount++;
    if (daysCount >= 7) break;
  }

  resultText += "Para reservar a sua mesa, basta digitar *1* ou acessar o link abaixo:\n🔗 http://localhost:5173/agendar";

  item.json.resultText = resultText;
}
return $input.all();

